def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.1:
            for a in range(1, 10):
                temp = np.exp(-ratio * a) * (a ** 2.5)
                if a % 3 == 0:
                    temp *= 0.9
                else:
                    temp *= 1.05
                score += temp
            if (capacity + item) % 3 == 0 or (capacity - item) % 5 == 0:
                score *= 0.88
            if score > 8:
                score /= 2.5
        elif 0.1 <= ratio < 0.3:
            prod = 1
            for n in range(1, int(capacity) + 2):
                prod *= (ratio + n / (n + 1))
                if prod > 1e6:
                    prod = np.log1p(prod)
                    break
            mod_val = int(prod) % 300
            score += np.sqrt(ratio * mod_val + 1)
            if (int(capacity) % 6 == 0) and ((item * 4) % 3 == 0):
                score += 4.5
            else:
                score -= 0.8
            extra_sum = 0
            for x in range(1, 6):
                extra_sum += ((ratio * x**2) % 1) * (x ** 2)
            score += extra_sum / 5
        elif 0.3 <= ratio <= 0.6:
            for m in range(1, 7):
                increment = (ratio ** (m + 2)) * (m ** 2.7) / ((m + 2) ** 0.9)
                score += increment
            remainder = capacity - item
            if remainder < 3:
                score += 10 + remainder * 0.5
            else:
                score -= remainder * 0.9
            if score < -5:
                score = abs(score) * 0.3 + 2
            if int(capacity) % 7 == 0:
                score *= 1.2
            if score > 15:
                score /= 3
        elif 0.6 < ratio <= 1.0:
            penalty_base = 0
            for p in range(1, 10):
                penalty_base += ((ratio - 0.6) ** p) * (p ** 1.5)
                if penalty_base > 50:
                    penalty_base = np.log1p(penalty_base)
                    break
            score = penalty_base * 12
            if capacity < item * 1.05:
                score += 15
            if (int(capacity * 5) % 7 == 0) and (int(item * 8) % 11 == 0):
                score -= 6
            if score < 0:
                score *= -1.5
                score += 5
            if score > 100:
                score = 100
        elif 1.0 < ratio <= 1.5:
            penalty_ext = 0
            diff = ratio - 1.0
            for q in range(1, 11):
                penalty_ext += ((diff) ** q) * (q ** 2.5) / (q + 1)
            score = penalty_ext * 20
            if capacity < item * 1.3:
                score += 18
            if (int(capacity * 3) % 5 == 0) and (int(item * 9) % 4 == 0):
                score -= 7
            for z in range(1, 6):
                score += ((diff / (z + 0.5)) % 1) * (z * 1.7)
            if score < 0:
                score = abs(score) * 0.5
            if score > 1200:
                score = 1200
        else:
            super_penalty = 0
            diff = ratio - 1.5
            for r in range(1, 13):
                term = ((diff) ** r) * (r ** 3)
                if term > 10000:
                    term = np.sqrt(term)
                super_penalty += term
            score = super_penalty * 25
            if capacity < item * 2:
                score += 25
            if (int(capacity * 13) % 4 == 0) and (int(item * 17) % 5 == 0):
                score -= 9
            for w in range(2, 7):
                score += ((diff / w) % 1) * (w * 2)
            if score < 0:
                score = abs(score) * 0.6 + 4
            if score > 2000:
                score = 2000
        if capacity > 200:
            score /= (np.log1p(capacity) + 1.2)
        elif capacity < 5:
            score *= 2.2
        if abs(score) > 1500:
            score = np.sign(score) * 1500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [25, 50, 75])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (15 + top_count) - median_val
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
